import fs from 'node:fs/promises';
import path from 'node:path';
import type { SyncConfig } from './config.js';

const GENERATED_MARKER = '// @generated by @hexagen/sync';

/**
 * Checks if a file was generated by the sync tool (safe to overwrite unless --force is false).
 */
export function isGeneratedFile(content: string): boolean {
  return content.includes(GENERATED_MARKER);
}

/**
 * Determines if a file is in the protected monorepo root area.
 */
export function isProtectedRoot(filePath: string, config: SyncConfig): boolean {
  const protectedFiles = [
    'package.json',
    'tsconfig.json',
    'tsconfig.base.json',
    '.architecture.yaml',
    'turbo.json',
    'yarn.lock',
    '.gitignore',
  ];
  const relative = path.relative(process.cwd(), filePath);
  const isRootLevel =
    !relative.startsWith('packages/') && !relative.startsWith('tools/');
  return isRootLevel && protectedFiles.some((f) => relative.endsWith(f));
}

/**
 * Safe, idempotent file writer that respects dry-run, force, protected root rules.
 * Returns status for accurate counter tracking.
 */
export async function safeWriteFile(
  filePath: string,
  content: string,
  config: SyncConfig
): Promise<'created' | 'updated' | 'unchanged' | 'skipped'> {
  const { dryRun, force, forceRoot, logger } = config;
  const relativePath = path.relative(process.cwd(), filePath);

  // Ensure directory exists (idempotent)
  await fs.mkdir(path.dirname(filePath), { recursive: true });

  let exists = false;
  let currentContent = '';
  try {
    currentContent = await fs.readFile(filePath, 'utf8');
    exists = true;
  } catch (e: any) {
    if (e.code !== 'ENOENT') {
      logger.error(`Failed to read ${relativePath}: ${e.message}`);
      throw e;
    }
  }

  // Content unchanged → early exit
  if (exists && currentContent === content) {
    logger.info(`unchanged ${relativePath}`);
    return 'unchanged';
  }

  // Dry-run simulation
  if (dryRun) {
    logger.info(
      `[DRY-RUN] would ${exists ? 'update' : 'create'} ${relativePath}`
    );
    return exists ? 'updated' : 'created';
  }

  // Protection checks
  if (exists && !force && !isGeneratedFile(currentContent)) {
    logger.warn(`skipped (protected, use --force) ${relativePath}`);
    return 'skipped';
  }

  if (isProtectedRoot(filePath, config) && !forceRoot) {
    logger.warn(`skipped (root protected, use --force-root) ${relativePath}`);
    return 'skipped';
  }

  // Perform the write
  await fs.writeFile(filePath, content, 'utf8');
  const status = exists ? 'updated' : 'created';
  logger.info(`${status} ${relativePath}`);
  return status;
}
